code = """import json

# Load company info
with open(locals()['var_function-call-9049256654640604985'], 'r') as f:
    companies = json.load(f)
# Create a dict for symbol -> description
# The "Company Description" field seems to contain the company name at the beginning or is the description.
# The user asked for "company names". The field is "Company Description".
# I'll check if there's a Name field.
# Fields: Nasdaq Traded, Symbol, Listing Exchange, Market Category, ETF, Round Lot Size, Test Issue, Financial Status, NextShares, Company Description.
# Usually "Company Description" starts with the name. I will use the full description or try to extract the name if it looks like "Name Inc. is ...".
# Let's just use the description as the name reference or the symbol.
# I'll store symbol -> description.
sym_to_name = {c['Symbol']: c['Company Description'] for c in companies}

# Load Q1 results
with open(locals()['var_function-call-6782329025317807361'], 'r') as f:
    r1 = json.load(f)

# Load Q2 results
with open(locals()['var_function-call-6417572442287889954'], 'r') as f:
    r2 = json.load(f)

# Combine
results = r1 + r2

# Convert "Days" to int
for r in results:
    r['Days'] = int(r['Days'])

# Sort
results.sort(key=lambda x: x['Days'], reverse=True)

# Top 5
top5 = results[:5]

# Add company names
final_list = []
for item in top5:
    desc = sym_to_name.get(item['Symbol'], "Unknown")
    # Extract name from description? usually description is "Name ...".
    # I'll just provide the description as the name.
    final_list.append({"Symbol": item['Symbol'], "Days": item['Days'], "Company Name": desc})

print("__RESULT__:")
print(json.dumps(final_list))"""

